                                ×
                            </button>
                        </div>
                    ))}
                    {formData.skills.length === 0 && (
                        <p className="no-skills">No skills added yet</p>
                    )}
                </div>
            </div>

            <div className="section-actions">
                <button 
                    type="button"
                    className="btn-save-section"
                    onClick={handleSubmit}
                    disabled={updating}
                >
                    {updating ? 'Saving...' : 'Save Skills'}
