                                <span className="avail-label">Days:</span>
                                <span className="avail-value">
                                    {worker.available_days || 'Flexible'}
                                </span>
                            </div>
                            <div className="avail-item">
                                <span className="avail-label">Hours:</span>
                                <span className="avail-value">
                                    {worker.available_hours || 'Flexible'}
                                </span>
                            </div>
                        </div>
